using System.Text.Json;
using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["featureFlags"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false,
        }
    };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "Application Configuration",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/feature-flags",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns only the feature flag settings.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(AppConfig["featureFlags"], new JsonSerializerOptions { WriteIndented = true });
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back, useful for testing connectivity.")]
    public static string Echo(
        [Description("The message to echo back")] string message) =>
        $"Echo: {message}";
}

